import{_ as d,o as a,c as r,a2 as n}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"F06: 存貨與債務穩定度審計 - finance-financial-analyst 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6261_久元/20260424/F06_存貨與債務穩定度審計.md","filePath":"審計報告庫/財務審計/6261_久元/20260424/F06_存貨與債務穩定度審計.md"}'),e={name:"審計報告庫/財務審計/6261_久元/20260424/F06_存貨與債務穩定度審計.md"};function o(i,t,s,l,h,c){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="f06-存貨與債務穩定度審計-finance-financial-analyst-審計報告" tabindex="-1">F06: 存貨與債務穩定度審計 - finance-financial-analyst 審計報告 <a class="header-anchor" href="#f06-存貨與債務穩定度審計-finance-financial-analyst-審計報告" aria-label="Permalink to &quot;F06: 存貨與債務穩定度審計 - finance-financial-analyst 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>存貨金額變動趨勢為何？流動性資產是否足以覆蓋短期與長期債務？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>根據截至2025年12月最新公開數據，久元（6261）存貨水位自2023Q1的9.57億元攀升至2024Q4的13.76億元後回落至11.69億元，存貨週轉天數由94天拉長至約105天，顯示去化速度略有放緩。然而流動比率高達3.46倍、速動比2.52倍，現金及約當現金14.16億元遠超短期借款僅0.14億元，長期借款歸零，償債壓力極低。評級為 <strong>A（良）</strong> — 流動性充裕但存貨水位偏高需持續追蹤。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>A（良）</strong> — 久元的流動性資產結構極為健壯。截至2025Q4，現金及約當現金14.16億元佔流動資產的33.2%，流動負債僅12.35億元，流動比率3.46倍、速動比率2.52倍，均遠超安全水位。短期借款僅0.14億元（佔總資產0.17%），長期借款為零，整體負債比率僅18.14%，權益比率達81.86%。存貨方面，2023Q1至2025Q4的存貨趨勢為：9.57億 → 13.76億（2024Q4峰值）→ 11.69億，存貨佔營收比由25.8%上升至約30%，存貨週轉天數從94天（2023年）微幅拉長至105天（2025年），顯示存貨去化速度略有放緩但仍在合理範圍內。</p><table tabindex="0"><thead><tr><th>項目</th><th>2023Q1</th><th>2024Q1</th><th>2025Q1</th><th>2025Q4</th></tr></thead><tbody><tr><td>存貨（百萬元）</td><td>957</td><td>1,036</td><td>1,319</td><td>1,169</td></tr><tr><td>現金及約當現金（百萬元）</td><td>2,877</td><td>2,811</td><td>2,278</td><td>1,416</td></tr><tr><td>流動資產合計（百萬元）</td><td>5,082</td><td>5,429</td><td>5,023</td><td>4,273</td></tr><tr><td>流動負債合計（百萬元）</td><td>1,257</td><td>1,803</td><td>1,607</td><td>1,235</td></tr><tr><td>短期借款（百萬元）</td><td>148</td><td>0</td><td>33</td><td>14</td></tr><tr><td>長期借款（百萬元）</td><td>0</td><td>0</td><td>0</td><td>0</td></tr><tr><td>流動比率</td><td>4.04x</td><td>3.01x</td><td>3.13x</td><td>3.46x</td></tr><tr><td>速動比率（簡式）</td><td>3.28x</td><td>2.44x</td><td>2.30x</td><td>2.52x</td></tr><tr><td>現金/短借倍數</td><td>19.4x</td><td>—</td><td>69.0x</td><td>101.1x</td></tr></tbody></table><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>存貨趨勢分析：</strong> 久元的存貨在2023年Q1至Q4期間維持在9.6億至10.4億元區間，2024年Q4達到階段性高點13.76億元（較2023Q1增加43.8%），主因係公司擴充半導體測試設備相關存貨備料。2025年Q1至Q4存貨逐步回落至11.69億元，顯示公司積極去化過高庫存。年度存貨週轉天數計算：2023年約94天、2024年約95天、2025年約105天（以年末存貨/年度營收×365估算）。雖然2025年天數微幅拉長，但絕對值仍在半導體測試代工產業合理範圍內（一般90-120天）。值得注意的是，2025Q4存貨較2025Q1下降11.3%，顯示去化策略正在奏效。</p><p><strong>償債壓力測試：</strong> 久元的債務結構極為保守。2023Q1尚有短期借款1.48億元，但自2023Q2起已完全清償短期借款。長期借款方面，2023年Q2至Q4曾有約1.4億至1.5億元，但於2023年底前已全部償還。截至2025Q4，短期借款僅0.14億元、長期借款歸零。現金覆蓋倍數（現金/短期借款）高達101.1倍，代表即使所有短期債務同時到期，公司現金仍足以覆蓋超過100倍。流動比率3.46倍、速動比率2.52倍，遠高於一般企業安全水位（流動比&gt;2、速動比&gt;1）。</p><p><strong>營運週期評估：</strong> 以應收帳款淨額（2025Q4為13.38億元）搭配存貨計算，營運資金需求相對可控。2025Q4應收帳款週轉天數約達130天（以年度營收11.83億元估算），顯示客戶帳期偏長，但此為半導體測試代工產業常見現象。合約負債（2025Q4約1.53億元）佔營收比例約1.6%，反映預收款模式尚未成為主要營運特徵。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>從華爾街空頭視角審視，久元最顯著的風險點在於「存貨結構未披露細項」。FinMind數據僅提供存貨總額，無法區分原料、在製品與製成品的比例。若製成品佔比異常偏高，可能暗示終端訂單去化不如預期。建議投資人持續追蹤2025年法說會簡報中關於「存貨組成」的揭露，特別關注Mini LED與RFID產品線的庫存水位。</p><p>另一方面，久元的「零長期借款」策略雖極度保守，但也可能代表公司錯失了低利率環境下的槓桿擴張機會。在2023-2024年低利率期間，公司選擇提前償還所有長期借款而非用於資本支出擴張，這種「現金囤積型」策略在景氣下行時提供極強防禦力，但在上行週期中可能限制獲利爆發速度。</p><p>從正面來看，久元的資產負債表堪称「堡壘級」。現金佔總資產17%、流動資產佔比51.2%，加上幾乎零有息負債，公司具備極強的抗風險能力。即使半導體測試代工產業面臨景氣衰退，久元也能依靠現金儲備支撐至少3-4年的營運支出（以2025年年度營業成本約19.6億元推算）。</p><p><strong>物理對策：</strong> 投資人應在2025年法說會中確認：（1）存貨細項組成是否健康、（2）美國子公司營運進展是否帶動新增訂單、（3）未來一年資本支出計畫與資金來源。若存貨持續下降且現金使用率可控，則流動性評級可進一步上修至S。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>數據採集器查詢</strong>：<code>/Users/kaipro/.openclaw/skills/finmind/數據採集器.py balance_sheet 6261 2023-01-01 2026-04-24 --df</code>（科目：資產負債表全項目，數據截至2025Q4）</li><li><strong>數據採集器查詢</strong>：<code>/Users/kaipro/.openclaw/skills/finmind/數據採集器.py cash_flow 6261 2023-01-01 2026-04-24 --df</code>（科目：現金流量表，數據截至2025Q4）</li><li><strong>數據採集器查詢</strong>：<code>/Users/kaipro/.openclaw/skills/finmind/數據採集器.py revenue 6261 2023-01-01 2026-04-24 --df</code>（科目：月營收，數據截至2026Q1）</li><li><strong>公開資訊觀測站</strong>：久元電子2025年第4季財務報告書（董事會通過日期：2026/03/09）</li><li><strong>Goodinfo!</strong>：<a href="https://goodinfo.tw/tw/BasicInfo.asp?STOCK_ID=6261" target="_blank" rel="noreferrer">6261 久元基本資料</a>（資本額12.85億元、市值約100.61億）</li><li><strong>法說會摘要</strong>：富果網 2025/08/28 久元法說會重點內容（上半年營收19.5億、毛利率28%）</li></ul>',19)])])}const f=d(e,[["render",o]]);export{_ as __pageData,f as default};
